module top_module(
    A,
    B,
    Cin,
    Clk,
    S,
    Cout
);input [3:0] A;
    input [3:0] B;
    input Cin;
    input Clk;
    output reg [3:0] S;  // Changed to reg type
    output reg Cout;      // Changed to reg type

    wire [3:0] sum;
    wire carry;

    // Carry bits calculation
      wire _n01 = A + B[0] ^ Cin[0];
  wire _c01 = A + B[0] & Cin[0];
  wire _n02 = A + B[1] ^ Cin[1] ^ _c01;
  wire _c02 = (A + B[1] & Cin[1]) | (A + B[1] & _c01) | (Cin[1] & _c01);
  wire _n03 = A + B[2] ^ Cin[2] ^ _c02;
  wire _c03 = (A + B[2] & Cin[2]) | (A + B[2] & _c02) | (Cin[2] & _c02);
  wire _n04 = A + B[3] ^ Cin[3] ^ _c03;
  wire _c04 = (A + B[3] & Cin[3]) | (A + B[3] & _c03) | (Cin[3] & _c03);
  assign sum = {_n01, _n02, _n03, _n04};
    assign carry = (A[3] & B[3]) | (Cin & (A[3] ^ B[3]));

    always @(posedge Clk) begin
        S <= sum;
        Cout <= carry;      // Updated to use correct carry wire
    end

endmodule
